mapper.select:
SELECT /* @SQLID=SUB0505_02-01#Sql002 */ N.wholeCount, N.lectureId, N.title, N.employeeId, N.employeeName, N.branchNameOfBranch, N.userId, N.confirmDateTime, N.viewReportUser, N.corBrowseFlag, N.codeName, N.brokerCode FROM( SELECT COUNT(*) OVER() AS wholeCount, M.lectureId, M.title, M.employeeId, M.employeeName, M.branchNameOfBranch, M.userId, A.COR_CONFIRMATION_DATE AS confirmDateTime, A.COR_UPDATE_BY, CASE WHEN M.userId <> A.COR_UPDATE_BY THEN MU2.USER_NM ELSE NULL END AS viewReportUser, B.COR_BROWSE_FLAG AS corBrowseFlag, CM.CODE_NAME AS codeName, M.brokerCode FROM( SELECT MU.USER_ID AS userId, MU.EMPLOYEE_ID AS employeeId, MU.USER_NM AS employeeName, MU.BROKER_ID AS brokerCode, MU.SUB_BROKER_ID, MU.BRANCH_ID, CC.COR_LEC_ID AS lectureId, CC.COR_TITLE AS title, CC.COR_COMMUNICATION_DATE AS comDate, MB.BRANCH_NAME AS branchNameOfBranch FROM COR_COMPLIANCE_COMMUNICATION CC, TB_MED_USERS MU
INNER JOIN MEDIATE_BRANCH MB ON MU.BROKER_ID = MB.BROKER_CODE AND MB.BROKER_BRANCH_KIND = '00' AND UTL_I18N.TRANSLITERATE(UPPER(TO_MULTI_BYTE(MB.BRANCH_NAME)),'kana_fwkatakana') LIKE '%'|| UTL_I18N.TRANSLITERATE(UPPER(TO_MULTI_BYTE(#{req.brokerName})), 'kana_fwkatakana')||'%'
LEFT JOIN MEDIATE_BRANCH MB ON MU.BROKER_ID = MB.BROKER_CODE AND MB.BROKER_BRANCH_KIND = '00'
WHERE MU.PRIV_ID <> '1' AND MU.PRIV_ID <> '2'
AND CC.COR_COMMUNICATION_DATE > (SELECT concat(to_char(IFA_DATE_UTIL.IFA_GET_DATE,'YYYY')- 5,to_char(IFA_DATE_UTIL.IFA_GET_DATE,'MM')) FROM DUAL) AND CC.COR_COMMUNICATION_DATE <= (SELECT concat(to_char(IFA_DATE_UTIL.IFA_GET_DATE,'YYYY'),to_char(IFA_DATE_UTIL.IFA_GET_DATE,'MM')) FROM DUAL)
AND CC.COR_COMMUNICATION_DATE > (SELECT concat(to_char(IFA_DATE_UTIL.IFA_GET_DATE,'YYYY')- 5,to_char(IFA_DATE_UTIL.IFA_GET_DATE,'MM')) FROM DUAL) AND CC.COR_COMMUNICATION_DATE < (SELECT concat(to_char(IFA_DATE_UTIL.IFA_GET_DATE,'YYYY'),to_char(IFA_DATE_UTIL.IFA_GET_DATE,'MM')) FROM DUAL)
AND CC.COR_COMMUNICATION_DATE = (SELECT concat(to_char(IFA_DATE_UTIL.IFA_GET_DATE,'YYYY'),to_char(IFA_DATE_UTIL.IFA_GET_DATE,'MM')) FROM DUAL)
)M LEFT JOIN COR_COMPLIANCE_CONFIRMATION A ON M.lectureId = A.COR_LEC_ID AND M.userId = A.COR_USER_ID LEFT JOIN COR_BROWSE_CONTROL_INDV B ON M.userId = B.COR_USER_ID LEFT JOIN CORDYS_CODE_MASTER CM ON CM.FUNCTION_ID = '013' AND A.COR_CONFIRMATION_FLG = CM.CODE_ID LEFT JOIN TB_MED_USERS MU2 ON A.COR_UPDATE_BY = MU2.USER_ID AND MU2.PRIV_ID = '1' WHERE 1=1
AND M.employeeName LIKE '%'||#{req.brokerChargeName}||'%'
AND M.title = #{req.title}
AND A.COR_CONFIRMATION_FLG = #{req.viewStatus}
AND ( A.COR_CONFIRMATION_FLG IS NULL OR A.COR_CONFIRMATION_FLG = #{req.viewStatus})
AND M.BRANCH_ID = #{req.branchId}
AND (B.COR_BROWSE_FLAG IS NULL OR B.COR_BROWSE_FLAG = #{req.viewNecessity})
AND B.COR_BROWSE_FLAG = #{req.viewNecessity}
ORDER BY M.comDate DESC, M.brokerCode )N WHERE 1=1
AND ROWNUM <= #{req.rownum}

SELECT /* @SQLID=SUB0505_02-01#Sql005 */ COUNT(1) AS count FROM ( SELECT USE.USER_ID, USE.USER_NM, USE.BROKER_ID, USE.BRANCH_ID, COM.COR_LEC_ID, COM.COR_TITLE, COM.COR_COMMUNICATION_DATE, BRA.BRANCH_NAME FROM COR_COMPLIANCE_COMMUNICATION COM, TB_MED_USERS USE
INNER JOIN MEDIATE_BRANCH BRA ON USE.BROKER_ID = BRA.BROKER_CODE AND BRA.BROKER_BRANCH_KIND = '00' AND UTL_I18N.TRANSLITERATE(UPPER(TO_MULTI_BYTE(BRA.BRANCH_NAME)),'kana_fwkatakana') LIKE '%'|| UTL_I18N.TRANSLITERATE(UPPER(TO_MULTI_BYTE(#{req.brokerName})), 'kana_fwkatakana')||'%'
LEFT JOIN MEDIATE_BRANCH BRA ON USE.BROKER_ID = BRA.BROKER_CODE AND BRA.BROKER_BRANCH_KIND = '00'
WHERE USE.PRIV_ID <> '1' AND USE.PRIV_ID <> '2' AND COM.COR_COMMUNICATION_DATE > (SELECT concat(to_char(IFA_DATE_UTIL.IFA_GET_DATE,'YYYY')- 5,to_char(IFA_DATE_UTIL.IFA_GET_DATE,'MM')) FROM DUAL) AND COM.COR_COMMUNICATION_DATE <= (SELECT concat(to_char(IFA_DATE_UTIL.IFA_GET_DATE,'YYYY'),to_char(IFA_DATE_UTIL.IFA_GET_DATE,'MM')) FROM DUAL) ) N LEFT JOIN COR_COMPLIANCE_CONFIRMATION CON ON N.COR_LEC_ID = CON.COR_LEC_ID AND N.USER_ID = CON.COR_USER_ID LEFT JOIN CORDYS_CODE_MASTER MAS ON MAS.FUNCTION_ID = '013' AND CON.COR_CONFIRMATION_FLG = MAS.CODE_ID LEFT JOIN COR_BROWSE_CONTROL_INDV IND ON N.USER_ID = IND.COR_USER_ID
N.USER_NM LIKE '%'||#{req.brokerChargeName}||'%'
AND N.COR_TITLE = #{req.title}
AND (CON.COR_CONFIRMATION_FLG IS NULL OR CON.COR_CONFIRMATION_FLG = #{req.viewStatus})
AND CON.COR_CONFIRMATION_FLG = #{req.viewStatus}
AND N.BRANCH_ID = #{req.branchId}
AND (IND.COR_BROWSE_FLAG IS NULL OR IND.COR_BROWSE_FLAG = #{req.viewNecessity})
AND IND.COR_BROWSE_FLAG = #{req.viewNecessity}

mapper.delete:
DELETE /* @SQLID=SUB0505_02-01#Sql007 */
FROM
    CORDYS.COR_COMPLIANCE_CONFIRMATION
WHERE
    COR_LEC_ID = #{req.lectureId}
    AND COR_USER_ID = #{req.userId}
